import{_ as c,r as n,o as d,c as u,a as e,b as t,t as r,d as o,w as f,e as p}from"./app-d223f2a5.js";const y={},w={id:"frontmatter-title-관련",tabindex:"-1"},m=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),_={class:"table-of-contents"},g=e("hr",null,null,-1),k=e("h2",{id:"expanding-your-horizons",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#expanding-your-horizons","aria-hidden":"true"},"#"),t(" Expanding your horizons")],-1),b=e("p",null,"Today marks the start of the second half of this course – you’ve finished the first 50 days now, and it’s time for the second 50 days. So, today we’re going to do something a little different: I want to give you a sense of the broader Swift ecosystem.",-1),v={href:"https://www.hackingwithswift.com/articles/165/the-best-swift-and-ios-conferences-in-2019",target:"_blank",rel:"noopener noreferrer"},x={href:"https://www.hackingwithswift.com/articles/152/conference-report-2018",target:"_blank",rel:"noopener noreferrer"},I={href:"https://www.hackingwithswift.com/articles/48/top-swift-and-ios-conferences-in-2018",target:"_blank",rel:"noopener noreferrer"},S=p("<p>While you’re just learning it’s easy to miss just how interesting our community is, so today I would you like you to watch two talks I’ve given at conferences last year: dotSwift in Paris and NSSpain in Logroño.</p><p>I’ve picked out these talks for different reasons:</p><ul><li>At this point in your learning, the dotSwift talk will be totally within your grasp, but will still inspire you to write better Swift code.</li><li>The NSSpain talk will about 70% in your grasp, and about 30% new, but I think at this point you’ll appreciate some of the many pain points I talk about.</li></ul><p>Don’t worry if there are some things you don’t fully understand yet. When you listen to a conference talk, very often you’ll know some things already, learn a few things quickly, and have to do some extra research on others – that’s normal, and it shows that it hit the sweet spot.</p><p>As I write this, I spoke to someone just yesterday who said they attended a conference in 2018 and then again in 2019, and it was amazing for them to see how much more they understood after a year of work. As Leonardo da Vinci said, “the noblest pleasure is the joy of understanding,” and I can think of few better yardsticks of your progress than watching talks live or recorded and realizing they are starting to make more sense than before.</p><p>Hopefully this video day gives you a little time to catch your breath, while also giving you just a taste of what else is out there.</p><p><strong>Today you have two videos to watch, and you’ll learn about <code>map()</code>, <code>flatMap()</code>, <code>filter()</code>, and more.</strong></p>",7),z=e("blockquote",null,[e("p",null,"Elements of Functional Programming")],-1),E=e("blockquote",null,[e("p",null,"Teaching Swift at Scale")],-1);function T(i,V){const s=n("router-link"),a=n("ExternalLinkIcon"),l=n("YouTube"),h=n("VideoPlayer");return d(),u("div",null,[e("h1",w,[m,t(" "+r(i.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,r(i.$frontmatter.description),1)]),e("nav",_,[e("ul",null,[e("li",null,[o(s,{to:"#expanding-your-horizons"},{default:f(()=>[t("Expanding your horizons")]),_:1})])])]),g,k,b,e("p",null,[t("I "),e("a",v,[t("often"),o(a)]),t(),e("a",x,[t("write"),o(a)]),t(" about "),e("a",I,[t("conferences"),o(a)]),t(", because I believe most people benefit from getting out there and meeting other people, hearing fresh ideas, and playing an active role in the community.")]),S,o(l,{id:"OgU8d_E1K14"}),z,o(h,{src:"https://vimeo.com/291590798"}),E])}const j=c(y,[["render",T],["__file","51.html.vue"]]);export{j as default};
